CREATE TABLE IF NOT EXISTS messages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), chat_id UUID NOT NULL REFERENCES chats(id), sender_id UUID REFERENCES users(id), sender_agent_id UUID, content TEXT NOT NULL, message_type VARCHAR(20) DEFAULT 'text', is_hidden BOOLEAN DEFAULT false, metadata JSONB DEFAULT '{}', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());